import{_ as t,o,c as i,ag as n}from"./chunks/framework.DUvHsH_U.js";const p=JSON.parse('{"title":"Login Setup","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/login-setup.md","filePath":"getting-started/login-setup.md","lastUpdated":1777975835000}'),s={name:"getting-started/login-setup.md"};function r(l,e,a,h,g,c){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="login-setup" tabindex="-1">Login Setup <a class="header-anchor" href="#login-setup" aria-label="Permalink to &quot;Login Setup&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This setup allows customers to log in to the mobile app using their mobile number and password.</p><p>When this setup is correct, testers can enter a customer&#39;s mobile number on the login screen, tap <strong>Login</strong>, and continue into the app without account or activation errors.</p><h2 id="erpnext-setup-steps" tabindex="-1">ERPNext Setup Steps <a class="header-anchor" href="#erpnext-setup-steps" aria-label="Permalink to &quot;ERPNext Setup Steps&quot;">​</a></h2><ol><li><p><strong>Log in as an Administrator</strong></p><ul><li>Open the ERPNext admin dashboard.</li><li>Log in with a System Manager or Administrator account.</li></ul></li><li><p><strong>Allow login with mobile number</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <code>System Settings</code> and open it.</li><li>Scroll to the <strong>Login</strong> section.</li><li>Enable the checkbox <strong>Allow Login using Mobile Number</strong>.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Confirm the customer user has a mobile number</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <code>User List</code> and open it.</li><li>Search for the customer user.</li><li>Open the user document.</li><li>Confirm the <strong>Mobile No</strong> field is filled in.</li><li>Confirm the mobile number exactly matches the number the tester will enter in the app.</li><li>Confirm the user is <strong>Enabled</strong>.</li><li>Click <strong>Save</strong> if you make any changes.</li></ul></li><li><p><strong>Confirm the customer account is connected</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <code>Customer List</code> and open it.</li><li>Search for the customer.</li><li>Open the customer document.</li><li>Confirm the customer is connected to the correct user according to the client&#39;s ERPNext setup.</li><li>Save the customer document if you make any changes.</li><li><strong>Reminder:</strong> If the ERPNext setup includes a <strong>shopping-cart-orders</strong> page, you can also connect the user to the customer directly through that page instead of manually editing the customer document.</li></ul></li><li><p><strong>Test from the mobile app</strong></p><ul><li>Fully close and reopen the mobile app.</li><li>Open the login screen.</li><li>Enter the customer&#39;s mobile number.</li><li>Enter the customer&#39;s password.</li><li>Tap <strong>Login</strong>.</li><li>The app should show normal loading briefly, then continue into the home screen.</li></ul></li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ol><li><p><strong>If the app says the account does not exist even though the user is in ERPNext</strong></p><ul><li>This can happen if the mobile number in ERPNext is missing or different from the number entered in the app.</li><li>Open <strong>User List</strong>.</li><li>Search for the customer user.</li><li>Confirm the <strong>Mobile No</strong> field exactly matches the number tested in the app.</li><li>Open <strong>System Settings</strong>.</li><li>In the <strong>Login</strong> section, confirm <strong>Allow Login using Mobile Number</strong> is enabled.</li></ul></li><li><p><strong>If the app says the account is not activated</strong></p><ul><li>This means the user exists, but the related customer record is missing or not connected correctly.</li><li>Open <strong>Customer List</strong>.</li><li>Search for the customer.</li><li>Open the customer document.</li><li>Confirm the customer has the correct linked portal user or contact information according to the client&#39;s ERPNext setup.</li></ul></li><li><p><strong>If login keeps loading and then shows an error dialog</strong></p><ul><li>This usually means the app could not read <strong>Mobile E-Commerce Settings</strong> before starting the login check.</li><li>Open <strong>Mobile E-Commerce Settings</strong> in ERPNext and confirm the document exists and is saved.</li><li>Ask the ERPNext administrator to verify that the <strong>Guest</strong> role has <strong>Read</strong> permission for this settings document.</li></ul></li><li><p><strong>If the app shows “You do not have permission to access this resource” during login</strong></p><ul><li>This means the stored keys in <strong>Mobile E-Commerce Settings</strong> belong to a user without enough permissions.</li><li>Open <strong>User List</strong>.</li><li>Open the <strong>API User</strong>.</li><li>Add <strong>System Manager</strong> in the <strong>Roles</strong> section.</li><li>Save the user.</li><li>Generate fresh keys if needed, then update <strong>Mobile E-Commerce Settings</strong> again.</li></ul></li></ol>',8)])])}const m=t(s,[["render",r]]);export{p as __pageData,m as default};
